/**
 * Base Service with CRUD Operations
 *
 * Abstract base class for all services in E-Menum.
 * Provides common CRUD operations with automatic tenant isolation,
 * event emission, and validation support.
 *
 * @module core/base/base.service
 *
 * @example
 * ```typescript
 * @injectable()
 * export class MenuService extends BaseService<Menu, CreateMenuDto, UpdateMenuDto> {
 *   constructor(
 *     @inject(TOKENS.PrismaClient) prisma: PrismaClient,
 *     @inject(TOKENS.EventService) eventService: EventService,
 *   ) {
 *     super(prisma, eventService, 'menu');
 *   }
 *
 *   // Custom business logic
 *   async publish(id: string, orgId: string): Promise<Menu> {
 *     const menu = await this.findById(id, orgId);
 *     return this.update(id, orgId, { isPublished: true, publishedAt: new Date() });
 *   }
 * }
 * ```
 */

import { PrismaClient } from '@prisma/client';
import { ZodSchema, ZodError } from 'zod';

import { AppException, ValidationError } from '@/core/exceptions/app.exception';
import { notDeleted, softDelete as softDeleteData } from '@/config/database';
import {
  BaseEntity,
  PaginatedResult,
  QueryParams,
  BaseRepository,
} from '@/core/base/base.repository';

// -----------------------------------------------------------------------------
// Types & Interfaces
// -----------------------------------------------------------------------------

/**
 * Event service interface for cross-module communication
 */
export interface IEventService {
  /**
   * Emits an event with the given name and payload
   */
  emit(eventName: string, payload: Record<string, unknown>): Promise<void>;
}

/**
 * Service context containing tenant and user information
 */
export interface ServiceContext {
  /** Organization/tenant ID for multi-tenancy */
  organizationId: string;
  /** Current user ID (optional) */
  userId?: string;
  /** Current user roles (optional) */
  roles?: string[];
}

/**
 * Options for service operations
 */
export interface ServiceOperationOptions {
  /** Skip event emission for this operation */
  skipEvents?: boolean;
  /** Skip validation for this operation */
  skipValidation?: boolean;
  /** Custom transaction client */
  tx?: unknown;
}

/**
 * Options for findAll operations
 */
export interface FindAllOptions<TEntity> extends QueryParams<TEntity> {
  /** Additional where filters */
  filters?: Record<string, unknown>;
}

/**
 * Options for delete operations
 */
export interface DeleteOptions extends ServiceOperationOptions {
  /** Whether to force hard delete (dangerous, use with caution) */
  hardDelete?: boolean;
}

// -----------------------------------------------------------------------------
// Constants
// -----------------------------------------------------------------------------

/** Default number of items per page */
const DEFAULT_PER_PAGE = 20;

/** Maximum number of items per page */
const MAX_PER_PAGE = 100;

/** Default sort order */
const DEFAULT_SORT_ORDER = 'desc' as const;

// -----------------------------------------------------------------------------
// Base Service Class
// -----------------------------------------------------------------------------

/**
 * Abstract base service with multi-tenant support and CRUD operations.
 *
 * This class provides a standardized approach to service implementation,
 * enforcing tenant isolation, soft deletes, and event-driven architecture.
 *
 * @typeParam TEntity - The entity type this service manages
 * @typeParam TCreateInput - Input type for create operations
 * @typeParam TUpdateInput - Input type for update operations
 *
 * @remarks
 * - All operations automatically filter by organizationId
 * - Soft delete is enforced by default
 * - Events are emitted for create, update, and delete operations
 * - Override hook methods for custom pre/post processing
 *
 * @example
 * ```typescript
 * @injectable()
 * export class CategoryService extends BaseService<Category, CreateCategoryDto, UpdateCategoryDto> {
 *   constructor(
 *     @inject(TOKENS.PrismaClient) prisma: PrismaClient,
 *     @inject(TOKENS.EventService) eventService: EventService,
 *   ) {
 *     super(prisma, eventService, 'category');
 *   }
 *
 *   // Override validation schema
 *   protected get createSchema(): ZodSchema | null {
 *     return CreateCategorySchema;
 *   }
 *
 *   // Override post-create hook
 *   protected async afterCreate(entity: Category, orgId: string): Promise<void> {
 *     await this.updateMenuCategoryCount(entity.menuId);
 *   }
 * }
 * ```
 */
export abstract class BaseService<
  TEntity extends BaseEntity,
  TCreateInput extends Record<string, unknown> = Record<string, unknown>,
  TUpdateInput extends Record<string, unknown> = Record<string, unknown>,
> {
  /**
   * The Prisma model name (lowercase) for dynamic access
   */
  protected readonly modelName: string;

  /**
   * Prisma client instance for database operations
   */
  protected readonly prisma: PrismaClient;

  /**
   * Event service for cross-module communication
   */
  protected readonly eventService?: IEventService;

  /**
   * Optional repository for complex data access
   */
  protected readonly repository?: BaseRepository<TEntity, TCreateInput, TUpdateInput>;

  /**
   * Creates a new BaseService instance
   *
   * @param prisma - Prisma client instance
   * @param eventService - Optional event service for event emission
   * @param modelName - Name of the Prisma model (lowercase)
   * @param repository - Optional repository for data access
   */
  constructor(
    prisma: PrismaClient,
    eventService: IEventService | undefined,
    modelName: string,
    repository?: BaseRepository<TEntity, TCreateInput, TUpdateInput>
  ) {
    this.prisma = prisma;
    this.eventService = eventService;
    this.modelName = modelName;
    this.repository = repository;
  }

  // ---------------------------------------------------------------------------
  // Validation Schemas (Override in subclass)
  // ---------------------------------------------------------------------------

  /**
   * Zod schema for validating create input
   * Override in subclass to enable validation
   */
  protected get createSchema(): ZodSchema | null {
    return null;
  }

  /**
   * Zod schema for validating update input
   * Override in subclass to enable validation
   */
  protected get updateSchema(): ZodSchema | null {
    return null;
  }

  // ---------------------------------------------------------------------------
  // Read Operations
  // ---------------------------------------------------------------------------

  /**
   * Finds all entities for an organization with pagination
   *
   * @param organizationId - Organization ID for tenant isolation
   * @param options - Query options (pagination, sorting, filters)
   * @returns Paginated list of entities
   *
   * @example
   * ```typescript
   * const result = await menuService.findAll('org_123', {
   *   page: 1,
   *   perPage: 10,
   *   sortBy: 'createdAt',
   *   sortOrder: 'desc',
   *   filters: { isPublished: true },
   * });
   * ```
   */
  async findAll(
    organizationId: string,
    options: FindAllOptions<TEntity> = {}
  ): Promise<PaginatedResult<TEntity>> {
    this.validateTenantContext(organizationId);

    const {
      page = 1,
      perPage = DEFAULT_PER_PAGE,
      sortBy,
      sortOrder,
      includeDeleted,
      filters = {},
    } = options;

    // Normalize pagination
    const normalizedPerPage = Math.min(Math.max(1, perPage), MAX_PER_PAGE);
    const normalizedPage = Math.max(1, page);
    const skip = (normalizedPage - 1) * normalizedPerPage;

    // Build where clause
    const where = {
      organizationId,
      ...(includeDeleted ? {} : notDeleted),
      ...filters,
    };

    // Build orderBy clause
    const orderBy = sortBy
      ? { [sortBy]: sortOrder || DEFAULT_SORT_ORDER }
      : { createdAt: DEFAULT_SORT_ORDER };

    // Execute count and find in parallel
    const [total, data] = await Promise.all([
      // @ts-expect-error - Dynamic model access
      this.prisma[this.modelName].count({ where }),
      // @ts-expect-error - Dynamic model access
      this.prisma[this.modelName].findMany({
        where,
        orderBy,
        skip,
        take: normalizedPerPage,
      }),
    ]);

    return {
      data,
      meta: {
        page: normalizedPage,
        perPage: normalizedPerPage,
        total,
        totalPages: Math.ceil(total / normalizedPerPage),
      },
    };
  }

  /**
   * Finds a single entity by ID with tenant isolation
   *
   * @param id - Entity ID
   * @param organizationId - Organization ID for tenant isolation
   * @returns The entity or null if not found
   *
   * @example
   * ```typescript
   * const menu = await menuService.findById('menu_123', 'org_123');
   * if (menu) {
   *   console.log(menu.name);
   * }
   * ```
   */
  async findById(id: string, organizationId: string): Promise<TEntity | null> {
    this.validateTenantContext(organizationId);

    // @ts-expect-error - Dynamic model access
    return this.prisma[this.modelName].findFirst({
      where: {
        id,
        organizationId,
        ...notDeleted,
      },
    });
  }

  /**
   * Finds a single entity by ID or throws an exception
   *
   * @param id - Entity ID
   * @param organizationId - Organization ID for tenant isolation
   * @returns The entity
   * @throws {AppException} When entity is not found (404)
   *
   * @example
   * ```typescript
   * try {
   *   const menu = await menuService.findByIdOrThrow('menu_123', 'org_123');
   *   console.log(menu.name);
   * } catch (e) {
   *   // Handle not found
   * }
   * ```
   */
  async findByIdOrThrow(id: string, organizationId: string): Promise<TEntity> {
    const entity = await this.findById(id, organizationId);

    if (!entity) {
      throw AppException.notFound(this.getResourceName(), id);
    }

    return entity;
  }

  /**
   * Finds a single entity by custom criteria with tenant isolation
   *
   * @param organizationId - Organization ID for tenant isolation
   * @param criteria - Additional where conditions
   * @returns The entity or null if not found
   *
   * @example
   * ```typescript
   * const menu = await menuService.findOne('org_123', { slug: 'main-menu' });
   * ```
   */
  async findOne(
    organizationId: string,
    criteria: Record<string, unknown>
  ): Promise<TEntity | null> {
    this.validateTenantContext(organizationId);

    // @ts-expect-error - Dynamic model access
    return this.prisma[this.modelName].findFirst({
      where: {
        organizationId,
        ...notDeleted,
        ...criteria,
      },
    });
  }

  /**
   * Checks if an entity exists with given criteria
   *
   * @param organizationId - Organization ID for tenant isolation
   * @param criteria - Where conditions to check
   * @returns True if entity exists
   *
   * @example
   * ```typescript
   * const exists = await menuService.exists('org_123', { slug: 'main-menu' });
   * if (exists) {
   *   throw AppException.alreadyExists('Menu', 'main-menu');
   * }
   * ```
   */
  async exists(organizationId: string, criteria: Record<string, unknown>): Promise<boolean> {
    this.validateTenantContext(organizationId);

    // @ts-expect-error - Dynamic model access
    const count = await this.prisma[this.modelName].count({
      where: {
        organizationId,
        ...notDeleted,
        ...criteria,
      },
    });

    return count > 0;
  }

  /**
   * Counts entities matching criteria
   *
   * @param organizationId - Organization ID for tenant isolation
   * @param criteria - Optional where conditions
   * @returns Count of matching entities
   *
   * @example
   * ```typescript
   * const activeCount = await menuService.count('org_123', { isPublished: true });
   * ```
   */
  async count(organizationId: string, criteria: Record<string, unknown> = {}): Promise<number> {
    this.validateTenantContext(organizationId);

    // @ts-expect-error - Dynamic model access
    return this.prisma[this.modelName].count({
      where: {
        organizationId,
        ...notDeleted,
        ...criteria,
      },
    });
  }

  // ---------------------------------------------------------------------------
  // Write Operations
  // ---------------------------------------------------------------------------

  /**
   * Creates a new entity with tenant association
   *
   * @param organizationId - Organization ID for tenant association
   * @param data - Entity creation data
   * @param options - Operation options
   * @returns The created entity
   *
   * @example
   * ```typescript
   * const menu = await menuService.create('org_123', {
   *   name: 'Main Menu',
   *   description: 'Our main offerings',
   * });
   * ```
   */
  async create(
    organizationId: string,
    data: TCreateInput,
    options: ServiceOperationOptions = {}
  ): Promise<TEntity> {
    this.validateTenantContext(organizationId);

    // Validate input if schema is provided
    let validatedData = data;
    if (!options.skipValidation && this.createSchema) {
      validatedData = this.validateInput(data, this.createSchema);
    }

    // Call pre-create hook
    await this.beforeCreate(validatedData, organizationId);

    // Create entity
    // @ts-expect-error - Dynamic model access
    const entity: TEntity = await this.prisma[this.modelName].create({
      data: {
        ...validatedData,
        organizationId,
      },
    });

    // Call post-create hook
    await this.afterCreate(entity, organizationId);

    // Emit event
    if (!options.skipEvents) {
      await this.emitEvent(`${this.modelName}.created`, {
        id: entity.id,
        organizationId,
        entity,
      });
    }

    return entity;
  }

  /**
   * Updates an entity with tenant isolation
   *
   * @param id - Entity ID
   * @param organizationId - Organization ID for tenant isolation
   * @param data - Entity update data
   * @param options - Operation options
   * @returns The updated entity
   * @throws {AppException} When entity is not found (404)
   *
   * @example
   * ```typescript
   * const menu = await menuService.update('menu_123', 'org_123', {
   *   name: 'Updated Menu Name',
   * });
   * ```
   */
  async update(
    id: string,
    organizationId: string,
    data: TUpdateInput,
    options: ServiceOperationOptions = {}
  ): Promise<TEntity> {
    this.validateTenantContext(organizationId);

    // Verify entity exists and belongs to organization
    const existing = await this.findByIdOrThrow(id, organizationId);

    // Validate input if schema is provided
    let validatedData = data;
    if (!options.skipValidation && this.updateSchema) {
      validatedData = this.validateInput(data, this.updateSchema);
    }

    // Call pre-update hook
    await this.beforeUpdate(existing, validatedData, organizationId);

    // Update entity
    // @ts-expect-error - Dynamic model access
    const entity: TEntity = await this.prisma[this.modelName].update({
      where: { id },
      data: validatedData,
    });

    // Call post-update hook
    await this.afterUpdate(entity, existing, organizationId);

    // Emit event
    if (!options.skipEvents) {
      await this.emitEvent(`${this.modelName}.updated`, {
        id: entity.id,
        organizationId,
        entity,
        changes: validatedData,
      });
    }

    return entity;
  }

  /**
   * Partially updates an entity (same as update, for semantic clarity)
   *
   * @param id - Entity ID
   * @param organizationId - Organization ID for tenant isolation
   * @param data - Partial entity update data
   * @param options - Operation options
   * @returns The updated entity
   */
  async patch(
    id: string,
    organizationId: string,
    data: Partial<TUpdateInput>,
    options: ServiceOperationOptions = {}
  ): Promise<TEntity> {
    return this.update(id, organizationId, data as TUpdateInput, options);
  }

  // ---------------------------------------------------------------------------
  // Delete Operations (Soft Delete by default)
  // ---------------------------------------------------------------------------

  /**
   * Soft deletes an entity (sets deletedAt timestamp)
   *
   * @param id - Entity ID
   * @param organizationId - Organization ID for tenant isolation
   * @param options - Delete options
   * @returns The soft-deleted entity
   * @throws {AppException} When entity is not found (404)
   *
   * @remarks
   * This performs a soft delete by default. The entity remains
   * in the database with deletedAt set.
   *
   * @example
   * ```typescript
   * await menuService.delete('menu_123', 'org_123');
   * ```
   */
  async delete(
    id: string,
    organizationId: string,
    options: DeleteOptions = {}
  ): Promise<TEntity> {
    this.validateTenantContext(organizationId);

    // Verify entity exists and belongs to organization
    const existing = await this.findByIdOrThrow(id, organizationId);

    // Call pre-delete hook
    await this.beforeDelete(existing, organizationId);

    let entity: TEntity;

    if (options.hardDelete) {
      // Hard delete (dangerous, use with caution)
      // @ts-expect-error - Dynamic model access
      entity = await this.prisma[this.modelName].delete({
        where: { id },
      });
    } else {
      // Soft delete (default)
      // @ts-expect-error - Dynamic model access
      entity = await this.prisma[this.modelName].update({
        where: { id },
        data: softDeleteData(),
      });
    }

    // Call post-delete hook
    await this.afterDelete(entity, organizationId);

    // Emit event
    if (!options.skipEvents) {
      await this.emitEvent(`${this.modelName}.deleted`, {
        id: entity.id,
        organizationId,
        hardDelete: options.hardDelete ?? false,
      });
    }

    return entity;
  }

  /**
   * Alias for delete() for semantic clarity
   *
   * @param id - Entity ID
   * @param organizationId - Organization ID for tenant isolation
   * @param options - Delete options
   * @returns The soft-deleted entity
   */
  async softDelete(
    id: string,
    organizationId: string,
    options: ServiceOperationOptions = {}
  ): Promise<TEntity> {
    return this.delete(id, organizationId, { ...options, hardDelete: false });
  }

  /**
   * Restores a soft-deleted entity
   *
   * @param id - Entity ID
   * @param organizationId - Organization ID for tenant isolation
   * @param options - Operation options
   * @returns The restored entity
   * @throws {AppException} When entity is not found (404)
   *
   * @example
   * ```typescript
   * const menu = await menuService.restore('menu_123', 'org_123');
   * ```
   */
  async restore(
    id: string,
    organizationId: string,
    options: ServiceOperationOptions = {}
  ): Promise<TEntity> {
    this.validateTenantContext(organizationId);

    // Find including deleted
    // @ts-expect-error - Dynamic model access
    const existing = await this.prisma[this.modelName].findFirst({
      where: {
        id,
        organizationId,
      },
    });

    if (!existing) {
      throw AppException.notFound(this.getResourceName(), id);
    }

    if (!existing.deletedAt) {
      throw AppException.badRequest(`${this.getResourceName()} is not deleted`);
    }

    // Restore entity
    // @ts-expect-error - Dynamic model access
    const entity: TEntity = await this.prisma[this.modelName].update({
      where: { id },
      data: { deletedAt: null },
    });

    // Emit event
    if (!options.skipEvents) {
      await this.emitEvent(`${this.modelName}.restored`, {
        id: entity.id,
        organizationId,
      });
    }

    return entity;
  }

  // ---------------------------------------------------------------------------
  // Hooks (Override in subclass for custom logic)
  // ---------------------------------------------------------------------------

  /**
   * Hook called before creating an entity
   * Override in subclass for custom pre-create logic
   *
   * @param _data - Entity creation data
   * @param _organizationId - Organization ID
   */
  protected async beforeCreate(
    _data: TCreateInput,
    _organizationId: string
  ): Promise<void> {
    // Override in subclass
  }

  /**
   * Hook called after creating an entity
   * Override in subclass for custom post-create logic
   *
   * @param _entity - Created entity
   * @param _organizationId - Organization ID
   */
  protected async afterCreate(_entity: TEntity, _organizationId: string): Promise<void> {
    // Override in subclass
  }

  /**
   * Hook called before updating an entity
   * Override in subclass for custom pre-update logic
   *
   * @param _existing - Existing entity before update
   * @param _data - Update data
   * @param _organizationId - Organization ID
   */
  protected async beforeUpdate(
    _existing: TEntity,
    _data: TUpdateInput,
    _organizationId: string
  ): Promise<void> {
    // Override in subclass
  }

  /**
   * Hook called after updating an entity
   * Override in subclass for custom post-update logic
   *
   * @param _entity - Updated entity
   * @param _previous - Entity state before update
   * @param _organizationId - Organization ID
   */
  protected async afterUpdate(
    _entity: TEntity,
    _previous: TEntity,
    _organizationId: string
  ): Promise<void> {
    // Override in subclass
  }

  /**
   * Hook called before deleting an entity
   * Override in subclass for custom pre-delete logic
   *
   * @param _entity - Entity being deleted
   * @param _organizationId - Organization ID
   */
  protected async beforeDelete(_entity: TEntity, _organizationId: string): Promise<void> {
    // Override in subclass
  }

  /**
   * Hook called after deleting an entity
   * Override in subclass for custom post-delete logic
   *
   * @param _entity - Deleted entity
   * @param _organizationId - Organization ID
   */
  protected async afterDelete(_entity: TEntity, _organizationId: string): Promise<void> {
    // Override in subclass
  }

  // ---------------------------------------------------------------------------
  // Helper Methods
  // ---------------------------------------------------------------------------

  /**
   * Gets the resource name for error messages
   * Override in subclass for custom resource names
   *
   * @returns Resource name (e.g., 'Menu', 'Category')
   */
  protected getResourceName(): string {
    return this.modelName.charAt(0).toUpperCase() + this.modelName.slice(1);
  }

  /**
   * Validates that the organizationId is provided
   *
   * @param organizationId - Organization ID to validate
   * @throws {AppException} When organizationId is missing
   */
  protected validateTenantContext(organizationId: string): void {
    if (!organizationId) {
      throw new AppException('TENANT_CONTEXT_MISSING', 400, {
        message: 'Organization ID is required for this operation',
      });
    }
  }

  /**
   * Validates input data against a Zod schema
   *
   * @param data - Input data to validate
   * @param schema - Zod schema to validate against
   * @returns Validated and parsed data
   * @throws {AppException} When validation fails
   */
  protected validateInput<T>(data: unknown, schema: ZodSchema<T>): T {
    try {
      return schema.parse(data);
    } catch (error) {
      if (error instanceof ZodError) {
        const validationErrors: ValidationError[] = error.errors.map((err) => ({
          field: err.path.join('.'),
          message: err.message,
          rule: err.code,
        }));
        throw AppException.validation(validationErrors);
      }
      throw error;
    }
  }

  /**
   * Emits an event via the event service
   *
   * @param eventName - Name of the event
   * @param payload - Event payload data
   */
  protected async emitEvent(
    eventName: string,
    payload: Record<string, unknown>
  ): Promise<void> {
    if (this.eventService) {
      try {
        await this.eventService.emit(eventName, payload);
      } catch (error) {
        // Log but don't fail the operation for event emission failures
        // eslint-disable-next-line no-console
        console.warn(`[BaseService] Event emission failed for '${eventName}':`, error);
      }
    }
  }

  /**
   * Builds a where clause with tenant isolation
   *
   * @param organizationId - Organization ID
   * @param additionalCriteria - Additional where conditions
   * @param includeDeleted - Whether to include soft-deleted records
   * @returns Complete where clause
   */
  protected buildWhereClause(
    organizationId: string,
    additionalCriteria: Record<string, unknown> = {},
    includeDeleted = false
  ): Record<string, unknown> {
    return {
      organizationId,
      ...(includeDeleted ? {} : notDeleted),
      ...additionalCriteria,
    };
  }
}

// -----------------------------------------------------------------------------
// Non-Tenant Base Service
// -----------------------------------------------------------------------------

/**
 * Base service for entities that don't require tenant isolation.
 * Use this for platform-level entities like Plan, Feature, etc.
 *
 * @typeParam TEntity - The entity type this service manages
 * @typeParam TCreateInput - Input type for create operations
 * @typeParam TUpdateInput - Input type for update operations
 *
 * @example
 * ```typescript
 * @injectable()
 * export class PlanService extends BaseNonTenantService<Plan, CreatePlanDto, UpdatePlanDto> {
 *   constructor(
 *     @inject(TOKENS.PrismaClient) prisma: PrismaClient,
 *     @inject(TOKENS.EventService) eventService: EventService,
 *   ) {
 *     super(prisma, eventService, 'plan');
 *   }
 * }
 * ```
 */
export abstract class BaseNonTenantService<
  TEntity extends Omit<BaseEntity, 'organizationId'>,
  TCreateInput extends Record<string, unknown> = Record<string, unknown>,
  TUpdateInput extends Record<string, unknown> = Record<string, unknown>,
> {
  protected readonly modelName: string;
  protected readonly prisma: PrismaClient;
  protected readonly eventService?: IEventService;

  constructor(
    prisma: PrismaClient,
    eventService: IEventService | undefined,
    modelName: string
  ) {
    this.prisma = prisma;
    this.eventService = eventService;
    this.modelName = modelName;
  }

  /**
   * Finds all entities with pagination
   */
  async findAll(options: QueryParams<TEntity> = {}): Promise<PaginatedResult<TEntity>> {
    const {
      page = 1,
      perPage = DEFAULT_PER_PAGE,
      sortBy,
      sortOrder,
      includeDeleted,
    } = options;

    const normalizedPerPage = Math.min(Math.max(1, perPage), MAX_PER_PAGE);
    const normalizedPage = Math.max(1, page);
    const skip = (normalizedPage - 1) * normalizedPerPage;

    const where = includeDeleted ? {} : notDeleted;
    const orderBy = sortBy
      ? { [sortBy]: sortOrder || DEFAULT_SORT_ORDER }
      : { createdAt: DEFAULT_SORT_ORDER };

    const [total, data] = await Promise.all([
      // @ts-expect-error - Dynamic model access
      this.prisma[this.modelName].count({ where }),
      // @ts-expect-error - Dynamic model access
      this.prisma[this.modelName].findMany({
        where,
        orderBy,
        skip,
        take: normalizedPerPage,
      }),
    ]);

    return {
      data,
      meta: {
        page: normalizedPage,
        perPage: normalizedPerPage,
        total,
        totalPages: Math.ceil(total / normalizedPerPage),
      },
    };
  }

  /**
   * Finds a single entity by ID
   */
  async findById(id: string): Promise<TEntity | null> {
    // @ts-expect-error - Dynamic model access
    return this.prisma[this.modelName].findFirst({
      where: { id, ...notDeleted },
    });
  }

  /**
   * Finds a single entity by ID or throws
   */
  async findByIdOrThrow(id: string): Promise<TEntity> {
    const entity = await this.findById(id);

    if (!entity) {
      throw AppException.notFound(this.getResourceName(), id);
    }

    return entity;
  }

  /**
   * Creates a new entity
   */
  async create(data: TCreateInput): Promise<TEntity> {
    // @ts-expect-error - Dynamic model access
    const entity: TEntity = await this.prisma[this.modelName].create({ data });

    await this.emitEvent(`${this.modelName}.created`, { id: entity.id, entity });

    return entity;
  }

  /**
   * Updates an entity
   */
  async update(id: string, data: TUpdateInput): Promise<TEntity> {
    await this.findByIdOrThrow(id);

    // @ts-expect-error - Dynamic model access
    const entity: TEntity = await this.prisma[this.modelName].update({
      where: { id },
      data,
    });

    await this.emitEvent(`${this.modelName}.updated`, { id: entity.id, entity });

    return entity;
  }

  /**
   * Soft deletes an entity
   */
  async delete(id: string): Promise<TEntity> {
    await this.findByIdOrThrow(id);

    // @ts-expect-error - Dynamic model access
    const entity: TEntity = await this.prisma[this.modelName].update({
      where: { id },
      data: softDeleteData(),
    });

    await this.emitEvent(`${this.modelName}.deleted`, { id: entity.id });

    return entity;
  }

  /**
   * Gets the resource name for error messages
   */
  protected getResourceName(): string {
    return this.modelName.charAt(0).toUpperCase() + this.modelName.slice(1);
  }

  /**
   * Emits an event via the event service
   */
  protected async emitEvent(
    eventName: string,
    payload: Record<string, unknown>
  ): Promise<void> {
    if (this.eventService) {
      try {
        await this.eventService.emit(eventName, payload);
      } catch (error) {
        // eslint-disable-next-line no-console
        console.warn(`[BaseNonTenantService] Event emission failed for '${eventName}':`, error);
      }
    }
  }
}
